import React from 'react';
import { Box, Icon, Text } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface TransactionItemProps extends SDUIComponentProps {
  icon: string;
  title: string;
  value: string;
  valueColor?: string;
  typeLabel?: string;
  showIcon?: boolean;
  mb?: string;
}

const VALUE_COLOR_MAP: Record<string, string> = {
  green: 'ACCEPT_COLOR_01',
  red: 'DENY_COLOR_01',
  gray: 'INTENSE_COLOR_03',
  orange: 'ALERT_COLOR_01',
};

export default function TransactionItemAdapter({
  props,
}: {
  props: TransactionItemProps;
  context: SDUIContext;
}) {
  const {
    icon,
    title,
    value,
    valueColor = 'green',
    typeLabel,
    showIcon = true,
    mb = 'xxxs',
  } = props;

  const resolvedColor = VALUE_COLOR_MAP[valueColor] ?? valueColor;

  return (
    <Box
      direction
      pd="squishSmall"
      mb={mb}
      align="center"
      bgColor="LIGHT_BASE_01"
      br="sm"
      style={{ minHeight: 56 }}
    >
      {showIcon && (
        <Box
          width={36}
          height={36}
          align="center"
          justify="center"
          bgColor="BRAND_COMPLEMENT_02"
          mr="xxxs"
          style={{ borderRadius: 18 }}
        >
          <Icon name={String(icon)} size="sm" color="INTENSE_COLOR_05" />
        </Box>
      )}
      <Box flex={1}>
        <Text type="paragraphMDM" numberOfLines={1}>
          {title}
        </Text>
        {typeLabel ? (
          <Text type="captionSM" color="INTENSE_COLOR_03">
            {typeLabel}
          </Text>
        ) : null}
      </Box>
      <Box align="flex-end">
        <Text type="paragraphMDM" color={resolvedColor}>
          {value}
        </Text>
      </Box>
    </Box>
  );
}

