  1â†’import React from 'react';
  2â†’import { View } from 'react-native';
  3â†’import type {
  4â†’  SDUIScreen,
  5â†’  SDUIComponent,
  6â†’  SDUIComponentRegistry,
  7â†’  SDUIComponentProps,
  8â†’  SDUIContext,
  9â†’  SDUIConditional,
 10â†’} from '../models';
 11â†’import { interpolateDeep } from '../utils/interpolation';
 12â†’import { evaluateRule } from '../utils/jsonLogic';
 13â†’import { getDefaultRegistry, getRenderer } from '../registry';
 14â†’import FallbackComponent from './FallbackComponent';
 15â†’
 16â†’interface ScreenRendererProps {
 17â†’  screen: SDUIScreen;
 18â†’  registry?: SDUIComponentRegistry;
 19â†’}
 20â†’
 21â†’function isConditional(value: unknown): value is SDUIConditional {
 22â†’  return (
 23â†’    value !== null &&
 24â†’    typeof value === 'object' &&
 25â†’    'rule' in (value as Record<string, unknown>) &&
 26â†’    typeof (value as Record<string, unknown>).rule === 'object'
 27â†’  );
 28â†’}
 29â†’
 30â†’function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
 31â†’  if (!component.visible) return true;
 32â†’  const { rule } = component.visible;
 33â†’  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
 34â†’    return true;
 35â†’  }
 36â†’  return evaluateRule(rule, context);
 37â†’}
 38â†’
 39â†’function separateConditionals(props: SDUIComponentProps): {
 40â†’  interpolatable: SDUIComponentProps;
 41â†’  conditionals: Record<string, SDUIConditional>;
 42â†’} {
 43â†’  const interpolatable: SDUIComponentProps = {};
 44â†’  const conditionals: Record<string, SDUIConditional> = {};
 45â†’
 46â†’  for (const key of Object.keys(props)) {
 47â†’    if (isConditional(props[key])) {
 48â†’      conditionals[key] = props[key] as SDUIConditional;
 49â†’    } else {
 50â†’      interpolatable[key] = props[key];
 51â†’    }
 52â†’  }
 53â†’
 54â†’  return { interpolatable, conditionals };
 55â†’}
 56â†’
 57â†’function renderComponent(
 58â†’  component: SDUIComponent,
 59â†’  context: SDUIContext,
 60â†’  registry: SDUIComponentRegistry,
 61â†’  key: string,
 62â†’) {
 63â†’  if (!isVisible(component, context)) return null;
 64â†’
 65â†’  const { interpolatable, conditionals } = separateConditionals(component.props);
 66â†’  const interpolatedProps = {
 67â†’    ...interpolateDeep(interpolatable, context),
 68â†’    ...conditionals,
 69â†’  };
 70â†’
 71â†’  const Renderer = getRenderer(registry, component.type);
 72â†’
 73â†’  if (!Renderer) {
 74â†’    return (
 75â†’      <FallbackComponent
 76â†’        key={key}
 77â†’        type={component.type}
 78â†’        props={interpolatedProps}
 79â†’      />
 80â†’    );
 81â†’  }
 82â†’
 83â†’  return <Renderer key={key} props={interpolatedProps} context={context} />;
 84â†’}
 85â†’
 86â†’export default function ScreenRenderer({
 87â†’  screen,
 88â†’  registry,
 89â†’}: ScreenRendererProps) {
 90â†’  const activeRegistry = registry ?? getDefaultRegistry();
 91â†’  const { context, header, body, footer } = screen;
 92â†’
 93â†’  return (
 94â†’    <View style={{ flex: 1 }}>
 95â†’      {header && renderComponent(header, context, activeRegistry, 'header')}
 96â†’
 97â†’      <View style={{ flex: 1 }}>
 98â†’        {(body ?? []).map((component, index) =>
 99â†’          renderComponent(
100â†’            component,
101â†’            context,
102â†’            activeRegistry,
103â†’            `${component.type}-${index}`,
104â†’          ),
105â†’        )}
106â†’      </View>
107â†’
108â†’      {footer && renderComponent(footer, context, activeRegistry, 'footer')}
109â†’    </View>
110â†’  );
111â†’}
