 3â†’const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;
 4â†’const DENIED_KEYS = new Set(['__proto__', 'constructor', 'prototype']);
 5â†’
 6â†’export function resolveContextPath(
 7â†’  context: SDUIContext,
 8â†’  path: string,
 9â†’): SDUIContextValue {
10â†’  const segments = path.trim().split('.');
11â†’  let current: SDUIContextValue = context;
12â†’
13â†’  for (const segment of segments) {
14â†’    if (current === null || current === undefined) return '';
15â†’    if (typeof current !== 'object') return '';
16â†’    if (DENIED_KEYS.has(segment)) return '';
17â†’
18â†’    if (Array.isArray(current)) {
19â†’      const index = parseInt(segment, 10);
20â†’      if (isNaN(index) || index < 0 || index >= current.length) return '';
21â†’      current = current[index] as SDUIContextValue;
22â†’    } else {
23â†’      current = (current as SDUIContext)[segment];
24â†’    }
25â†’  }
26â†’
27â†’  return current ?? '';
28â†’}
29â†’
30â†’export function interpolateString(
31â†’  template: string,
32â†’  context: SDUIContext,
33â†’): string {
34â†’  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
35â†’    const value = resolveContextPath(context, path);
36â†’    if (value === null || value === undefined) return '';
37â†’    if (typeof value === 'object') return '';
38â†’    return String(value);
39â†’  });
40â†’}
41â†’
42â†’export function interpolateDeep<T>(value: T, context: SDUIContext): T {
43â†’  if (typeof value === 'string') {
44â†’    return interpolateString(value, context) as T;
45â†’  }
46â†’
47â†’  if (Array.isArray(value)) {
48â†’    return value.map(item => interpolateDeep(item, context)) as T;
49â†’  }
50â†’
51â†’  if (value !== null && typeof value === 'object') {
52â†’    const result: Record<string, unknown> = {};
53â†’    for (const key of Object.keys(value)) {
54â†’      result[key] = interpolateDeep(
55â†’        (value as Record<string, unknown>)[key],
56â†’        context,
57â†’      );
58â†’    }
59â†’    return result as T;
60â†’  }
61â†’
62â†’  return value;
63â†’}
